// Example: ArticleDTO (from Strapi)
interface ArticleDTO {
  id: string
  attributes: {
    title: string
    slug: string
    content: RichText
    publishedAt: string
  }
}

// Validated at import with Zod
const ArticleDTOSchema = z.object({
  id: z.string(),
  attributes: z.object({
    title: z.string(),
    slug: z.string(),
    content: z.unknown(), // RichText
    publishedAt: z.string()
  })
})

// Example: mapArticleDTO()
function mapArticleDTO(dto: ArticleDTO): Article {
  return {
    id: dto.id,
    title: dto.attributes.title,
    slug: dto.attributes.slug,
    excerpt: computeExcerpt(dto.attributes.content), // ← Computed
    readTime: computeReadTime(dto.attributes.content), // ← Computed
    publishedAt: new Date(dto.attributes.publishedAt) // ← Parsed
  }
}

// Domain Model (flat, enriched)
interface Article {
  id: string
  title: string
  slug: string
  excerpt: string
  readTime: string
  publishedAt: Date
}

import 'server-only' // Prevents accidental client-side imports

interface ArticleRepository {
  getBySlug(slug: string): Promise<Article | null>
  listAll(): Promise<Article[]>
  listByCategory(category: string): Promise<Article[]>
  getRelated(slug: string): Promise<Article[]>
}

// Implementation: currently loads from JSON
export const articleRepository: ArticleRepository = {
  async getBySlug(slug: string) {
    const data = await loadJSON(`data/articles/${slug}.json`)
    const dto = ArticleDTOSchema.parse(data)
    return mapArticleDTO(dto)
  },
  // ... other methods
}

// Transform Article → ArticleDetailViewModel
interface ArticleDetailViewModel extends Article {
  formattedDate: string
  readTimeLabel: string
  relatedArticles: Article[]
}

function toArticleDetailViewModel(article: Article): ArticleDetailViewModel {
  return {
    ...article,
    formattedDate: new Intl.DateTimeFormat('en-US').format(article.publishedAt),
    readTimeLabel: `${article.readTime} min read`,
    relatedArticles: [] // Fetched separately if needed
  }
}

// app/articles/[slug]/page.tsx
export default async function ArticlePage({ params }) {
  const { slug } = params
  const article = await articleRepository.getBySlug(slug)

  if (!article) {
    notFound()
  }

  const viewModel = toArticleDetailViewModel(article)
  return <ArticleView {...viewModel} />
}
